import React, { useState, useEffect } from 'react';

const TableComponent = () => {
    const [records, setRecords] = useState([
        { id: 1, name: 'adam', age: 25 },
        { id: 2, name: 'james', age: 30 },
        { id: 3, name: 'nick', age: 28 },
        { id: 4, name: 'john', age: 29 }
    ]);
    const [sortField, setSortField] = useState('name');
    const [sortOrder, setSortOrder] = useState('asc');
    const [filterValue, setFilterValue] = useState('');

    // Filter function
    const filteredRecords = () => {
        const lowerCaseFilter = filterValue.toLowerCase();
        return records.filter(record => 
            record.name.toLowerCase().includes(lowerCaseFilter)
        );
    };

    // Sort function
    const sortedRecords = () => {
        const sorted = [...records];
        sorted.sort((a, b) => {
            const valueA = a[sortField];
            const valueB = b[sortField];
            if (valueA < valueB) return sortOrder === 'asc' ? -1 : 1;
            if (valueA > valueB) return sortOrder === 'asc' ? 1 : -1;
            return 0;
        });
        return sorted;
    };

    // Effect to handle changes in filter or sort
    useEffect(() => {
        const filtered = filteredRecords();
        const sorted = sortedRecords();
        setRecords(sorted);
    }, [filterValue, sortField, sortOrder]);

    // Handle filter change
    const handleFilterChange = (e) => {
        setFilterValue(e.target.value);
    };

    // Handle sort change
    const handleSortChange = (e) => {
        setSortField(e.target.value);
        setSortOrder(e.target.value === 'asc' ? 'asc' : 'desc');
    };

    return (
        <div>
            <div>
                <input
                    type="text"
                    placeholder="Filter by name..."
                    value={filterValue}
                    onChange={handleFilterChange}
                />
            </div>
